@ARTICLE{10.1007/s13105-026-01147-5,
	author = {Soria-Gondek A and Gonzalez-Riano C, Fernández-García P and Requena B, González L and Reyes-Farias M and Murillo M and Valls A and Real N and Villarroya F and Corrales P and Cereijo R and Herrero L and Barbas C, Sánchez-Infantes D},
	title = {Subcutaneous and visceral adipose tissue lipidome in children reveals novel lipid species involved in obesity.},
	journal = {J Physiol Biochem},
	year = {2026},
	abstract = {Overweight impacts over 390 million children and adolescents worldwide, of whom around 160 million are living with obesity. Adipose tissue biology in pediatric obesity is still relatively unknown. Adaptations to obesity including fat mobilization and remodeling are being investigated. The objective was to examine the lipidomic profile of subcutaneous and visceral adipose tissue (sWAT and vWAT, respectively) in children with obesity compared to those with normal weight, in order to identify novel lipid species modulated by obesity. Thirty pediatric patients with and without obesity were prospectively recruited at a referral single center and clinical data were reported. sWAT and vWAT samples were obtained for lipidomic analysis. Novel lipid species, including ether-linked triglycerides, ether-linked phosphatidylethanolamine, and oxidized triglycerides, were identified as altered in the sWAT from children with obesity compared with normal-weight children. These species are involved in beige adipose tissue development, energy metabolism, mitochondrial function, and oxidative stress. Compared with normal-weight children, the vWAT lipidome from children with obesity showed significant changes in some glycerophosphocholines, ceramides, and diglycerides, with accumulation of lipid species involved in inflammation, insulin resistance, and cardiovascular risk. The observed lipid correlations between vWAT and sWAT highlighted systemic dysregulation of lipid storage in childhood obesity, identifying both shared and depot-specific mechanisms of lipid handling. Our study reveals several critical lipid species that are modulated across both WAT depots, with notable implications for oxidative stress, lipid storage, and adipose tissue dysfunction. Key Points • The adipose lipidome of children with obesity showed specific alterations. • Lipid correlations revealed shared and depot-specific lipid handling mechanisms. • The altered lipid species had an impact on oxidative stress and insulin resistance.},
	doi = {10.1007/s13105-026-01147-5},
	pmid = {41535500 [Indexed for MEDLINE]},
	note = {PMC12804287}
}

@ARTICLE{10.1016/j.jnutbio.2026.110263,
	author = {Chan PC and Jhuang CH and Chang HY and Hsieh PS},
	title = {Brown adipocyte-derived SAA3-CPT1A axis regulates diet-induced thermogenesis and protects against obesity.},
	journal = {J Nutr Biochem},
	year = {2026},
	abstract = {Diet-induced thermogenesis (DIT), a critical component of energy expenditure driven by brown adipose tissue (BAT), is essential for maintaining metabolic health; however, its precise molecular regulation remains poorly understood. We investigated whether serum amyloid A3 (SAA3), a factor secreted by brown adipocytes, regulates DIT and protects against diet-induced obesity. Using two distinct mouse models: mice with brown adipocyte-specific Saa3 deletion and mice with lentiviral-mediated Saa3 overexpression in BAT, we examined energy expenditure, substrate utilization, and thermogenic responses under chow or short-term high-fat diet feeding. SAA3 expression in BAT was acutely induced by refeeding. Loss of SAA3 severely diminished postprandial DIT and total energy expenditure, leading to accelerated weight gain on a high-fat diet. Mechanistically, Saa3 deletion compromised uncoupling protein‐1 induction, chiefly by impairing adipose triglyceride lipase-driven lipolysis and, critically, by inhibiting carnitine palmitoyltransferase 1A (CPT1A)-dependent fatty acid oxidation (FAO). Conversely, SAA3 overexpression robustly enhanced DIT, stimulated lipolysis and FAO, and promoted mitochondrial oxidative phosphorylation. Studies in primary brown adipocytes confirmed that SAA3 deficiency reduced CPT1A expression, palmitate-stimulated lipolysis, and mitochondrial respiration. Together, these findings identify the SAA3-CPT1A axis as a novel, BAT-intrinsic mechanism that couples nutrient sensing to uncoupling protein‐11 function via enhanced FAO. By promoting lipid utilization and postprandial energy dissipation, SAA3 optimizes postprandial thermogenesis and defends against obesity, highlighting conserved SAA signaling as a potential nutritional and therapeutic target in metabolic disease.},
	doi = {10.1016/j.jnutbio.2026.110263},
	pmid = {41534602 [Indexed for MEDLINE]}
}

@ARTICLE{10.1152/ajpregu.00259.2025,
	author = {Bruzina AS and Crum BA and Goodman LA and Ng YE and Hawe RL and Call JA and Greising SM},
	title = {Novel assessment of postprandial metabolism reveals sex-specific metabolic flexibility and lipid remodeling following volumetric muscle loss.},
	journal = {Am J Physiol Regul Integr Comp Physiol},
	year = {2026},
	abstract = {Localized skeletal muscle injury [e.g., volumetric muscle loss (VML)] can disrupt diurnal metabolic flexibility. However, it remains unclear how the evaluation of whole body metabolism and physical activity following a prandial stimuli may reveal differences in metabolic flexibility between injured and uninjured states. This study aimed to develop a novel tool to examine whole body metabolic impairments following VML injury, with consideration of lipid-related mechanisms. Adult C57BL/6J mice (n = 50; equal males and females) were randomized to a methodology development cohort to undergo VML injury, intramuscular glycerol injection, or remain as controls. The developed tool using an intraperitoneal glucose injection and indirect calorimetry was used to characterize the dynamic nature of whole body metabolism. Whole body metabolism, in vivo muscle function, and markers of lipid and glycemic regulation were evaluated 6 wk following injury. Females, regardless of injury, exhibited greater daily energy expenditure alongside increases in activity. Females exhibit lower whole body lipid oxidation during the inactive period, despite higher in active period, suggesting more coordinated substrate utilization. Biological sex differences in postprandial substrate utilization reveal that males fail to suppress whole body lipid oxidation, exhibiting marked impairments in postprandial metabolic flexibility. VML injury increases protein expression of perilipin 2 and SIRT1 in the muscle remaining, while inducing sex-specific changes, with adipose triglyceride lipase (ATGL) expression markedly increased and with perilipin 5 expression markedly reduced in females. The remaining muscle following VML accumulates neutral lipids and perilipin 1-positive adipocytes. This work highlights sex-specific mechanisms of metabolic disruption following traumatic skeletal muscle injuries, such as VML.NEW & NOTEWORTHY We developed a novel, freely ambulatory preclinical tool to assess dynamic postprandial metabolic flexibility. Using this tool, we identified sex differences in whole body energy expenditure and substrate utilization. The use of a single intramuscular glycerol injection model is not sufficient as a comparative model for evaluating chronic ectopic lipid accumulation and metabolic disruptions. In the context of volumetric muscle loss injury, disruptions in metabolic flexibility occur alongside alterations in lipid handling and ectopic lipid accumulation.},
	doi = {10.1152/ajpregu.00259.2025},
	pmid = {41533362 [Indexed for MEDLINE]},
	note = {PMC12921476}
}

@ARTICLE{10.1021/acs.jafc.5c13938,
	author = {Yang R and Li X and Tang W and Qiu X and Ma W and Wu W and Wang M and Wang C and Zhao P and Wang H},
	title = {SCD-Mediated Oleic Acid-PPARγ Self-Reinforcing Loop Drives Porcine Intramuscular Fat Deposition.},
	journal = {J Agric Food Chem},
	year = {2026},
	abstract = {Intramuscular fat (IMF) deposition is a key determinant of pork quality and canonically regulated by peroxisome proliferator-activated receptor gamma (PPARγ). However, PPARγ expression levels do not always correlate directly with fat deposition, suggesting that transcript abundance alone is insufficient to account for the adipogenic potential. Here, we identified a self-reinforcing stearoyl-CoA desaturase (SCD)-oleic acid (OA)-PPARγ feedback loop that amplifies lipid metabolic gene expression and drives efficient IMF accumulation. Multilayer omics integration and functional assays showed that SCD-derived OA acts as an endogenous ligand to activate PPARγ, while PPARγ transcriptionally upregulates SCD, together amplifying a broad lipid metabolic gene network. Both SCD overexpression and OA-delivery nanoparticles consistently promoted IMF deposition in vivo, supporting the central role of this SCD-OA-PPARγ axis. Our findings reveal a conserved but dynamic feedback mechanism underlying IMF deposition and provide a molecular explanation for breed-specific differences in pork quality.},
	doi = {10.1021/acs.jafc.5c13938},
	pmid = {41528204 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cellsig.2026.112358,
	author = {Chen PQ and Wei YD and Zheng X and Xu QT and Xu SL and He S and Xu MJ and Ge JF},
	title = {Role of CTRP9 in obesity-associated microglial dysregulation: Promoting lipophagy via the PI3K/AKT/FOXO1 signaling pathway.},
	journal = {Cell Signal},
	year = {2026},
	abstract = {Activation of microglia triggers neuroinflammation, which subsequently leads to neurological dysfunction, representing a significant pathological mechanism underlying obesity-related cognitive impairment. Microglial lipophagy plays a critical role in regulating lipid homeostasis and inflammation; however, its involvement in obesity-related cognitive impairment remains largely unexplored. The accumulation of lipid droplets in microglia is a prominent feature of aging and reflects an imbalance in microglial lipid metabolism. CTRP9 is an important regulator in this process. The aim of this study was to investigate the potential role of CTRP9 in high-fat diet-induced disruption of microglial lipid metabolism. First, cognitive impairment was observed in an obesity model induced by a high-fat diet. We then observed a significant increase in lipid droplets in hippocampal microglia, inhibition of autophagic activity, and decreased CTRP9 expression in obese mice with cognitive impairment. Additionally, both BV2 and HMC3 cells stimulated with palmitic acid (PA) displayed lipid droplet accumulation, along with impaired lipophagy. Mechanistically, PA stimulation significantly reduced CTRP9 expression. To further investigate the role of CTRP9, we demonstrated that silencing CTRP9 exacerbated lipophagy impairment and increased lipid droplet accumulation in microglia. Conversely, overexpression of CTRP9 was able to reverse the aberrant activation of the PI3K/AKT/FOXO1 signaling pathway in PA-stimulated BV2 cells, thereby ameliorating these phenotypes. Taken together, these results suggest that CTRP9 plays a crucial regulatory role in lipid metabolism disorders in high-fat-stimulated microglia, and its mechanism may be closely linked to the dysfunction of the PI3K/AKT/FOXO1 signaling pathway.},
	doi = {10.1016/j.cellsig.2026.112358},
	pmid = {41525835 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jlr.2026.100978,
	author = {Jiao H, Cázarez-Márquez F and Rumanova VS and Wang Y and Kalsbeek A and Kramer G and Guo S and Yi CX},
	title = {Targeted PPARδ activation reprograms microglial immunometabolism and improves insulin sensitivity in HFD-fed rats.},
	journal = {J Lipid Res},
	year = {2026},
	abstract = {Microglia lipid metabolism plays a crucial role in maintaining immune function and supporting neuronal health. Previous studies have shown that a high-fat diet (HFD) promotes lipid accumulation in microglia, while disruption of lipid uptake and utilization impair neuroimmune competency and accelerate obesity in response to a HFD, highlighting the importance of lipid processing under obesogenic conditions. However, whether enhancing microglial lipid metabolism can restore their immune function and mitigate obesity-associated hypothalamic dysfunction remains unclear. In this study, we investigated whether activation of peroxisome proliferator-activated receptor delta (PPARδ), a key regulator of lipid metabolism, could counteract obesity-related metabolic disturbances. Using thermal proteome profiling, we identified GW0742 as the most potent PPARδ agonist among those tested. Treatment of microglial cells in vitro with GW0742 enhanced phagocytosis, reduced inflammation, and improved microglial metabolic flexibility. To assess therapeutic potential in vivo, we selectively delivering GW0742 to mediobasal hypothalamic microglia in HFD-fed rats using polymeric nanoparticles (NPs-GW0742). This targeted intervention reprogrammed microglial activity and improved insulin sensitivity without affecting body weight or food intake, suggesting a direct central metabolic benefit. Our findings highlight the therapeutic potential of targeting microglial lipid metabolism to improve metabolic health in obesity.},
	doi = {10.1016/j.jlr.2026.100978},
	pmid = {41519472 [Indexed for MEDLINE]},
	note = {PMC12874120}
}

@ARTICLE{10.1016/j.psj.2026.106376,
	author = {Wang Z and Wang D and Liu Y and Jian Z and Wang M and Lin H},
	title = {Identification of blood biomarkers associated with hepatic lipid accumulation in aging laying hens with fatty liver.},
	abstract = {Fatty Liver Hemorrhagic Syndrome (FLHS) is a metabolic disorder characterized by excessive hepatic triglycerides (TG) accumulation, primarily affecting high-producing, caged laying hens. In surviving hens, clinical signs are often subtle, making early diagnosis challenging. This study aimed to investigate the relationship between various blood parameters and hepatic fat deposition in late-phase laying hens under both fasting and fed conditions, with the goal of identifying reliable biomarkers for fatty liver (FL) diagnosis. Contrary to common assumptions, hepatic TG levels showed no significant correlation with classical blood lipid markers such as serum TG, total cholesterol (TCHO), and glucose (GLU) (P > 0.05). Under fasting conditions, hepatic TG content was positively correlated with albumin (ALB), total amino acids (TAA), and Leu (P < 0.05), while negatively correlated with α-aminobutyric acid (α-ABA), β-alanine (β-Ala), and β-aminoisobutyric acid (β-AiBA) (P < 0.05). Ala exhibited a highly significant negative correlation with liver TG (P < 0.001). Under fed conditions, hepatic TG levels were significantly positively correlated with alanine aminotransferase (ALT), the ALT/aspartate aminotransferase (AST) ratio (P < 0.05), and ALB (P < 0.001). Additionally, liver TG content was positively correlated with body weight (P < 0.05). Untargeted metabolomics identified 57 differentially expressed metabolites (VIP > 1, P < 0.05) between the NORM and FL groups, including 28 upregulated (e.g., taurodeoxycholic acid [TUDCA], taurolithocholic acid 3-sulfate [TLCAS], D-tryptophan), while 29 were downregulated (e.g., chenodeoxycholic acid, PC (18:0/14:0), PC 32:0). Functional enrichment analysis revealed these metabolites were significantly enriched in 67 metabolic pathways, particularly those related to protein digestion and absorption, amino acid biosynthesis, and bile secretion. Fasting-state biomarkers including plasma levels of TAA, Ala, Leu, D-tryptophan metabolites and bile acids (TUDCA, TLCAS), as well as fed-state serum ALB and ALT/AST ratio, may indicate FL. The present result provides theoretical basis and detection targets for the early diagnosis of fatty liver in laying hens, and offer theoretical support for the construction of precise nutritional intervention and non-invasive screening systems.},
	doi = {10.1016/j.psj.2026.106376},
	pmid = {41518905 [Indexed for MEDLINE]},
	note = {PMC12816915}
}

@ARTICLE{10.1152/ajpgi.00225.2025,
	author = {Jang H and Bae M and Lee Y and Kang H and Kim MB and Hu S and Corvino O and Lee J and Woo H and Kostour V and Odell W and Kim A and Park YK and Lee JY},
	title = {Loss of histone deacetylase 4 in hepatocytes perturbs lipid metabolism and insulin signaling in mice with diet-induced obesity.},
	journal = {Am J Physiol Gastrointest Liver Physiol},
	year = {2026},
	abstract = {Epigenetic regulations link environmental factors to the development of obesity and metabolic dysfunction-associated steatotic liver disease (MASLD). We determined the role of hepatocyte histone deacetylase 4 (HDAC4) in the pathogenesis of MASLD. Male and female hepatocyte-specific Hdac4 knockout (Hdac4HKO) mice and control Hdac4 floxed (Hdac4fl/fl) mice were fed a high-fat, high-sucrose, high-cholesterol diet for 16 wk to induce obesity and MASLD. The loss of hepatic Hdac4 increased serum alanine transaminase activity and exacerbated hepatic steatosis with higher liver weights and triglyceride levels than Hdac4fl/fl mice in males. Hepatic expression of lipogenic genes was significantly higher in male and female Hdac4HKO mice than in controls. Moreover, primary hepatocytes and the liver of Hdac4HKO mice exhibited perturbed insulin signaling, characterized by reduced phosphorylated AKT2. Interestingly, hepatocyte Hdac4 loss increased inflammatory and fibrogenic genes in gonadal white adipose tissue (gWAT). Serum cytokine array and proteomic analysis demonstrated alterations in several serum factors, which may contribute to crosstalk between the liver and WAT in Hdac4HKO, leading to obesity-induced metabolic dysfunction in gWAT. In conclusion, hepatocyte Hdac4 loss exacerbates hepatic steatosis, accompanied by disturbed insulin signaling and WAT inflammation and fibrosis in obese mice, underscoring its crucial role in liver-WAT crosstalk.NEW & NOTEWORTHY We examined the role of hepatocyte histone deacetylase 4 (HDAC4) in the development of obesity and metabolic dysfunction-associated steatotic liver disease (MASLD) using Hdac4-deficient mice with hepatocyte-specific deletion. We found that deleting Hdac4 in hepatocytes worsens hepatic steatosis and disrupts insulin signaling in the liver. In addition, this deletion caused inflammation and fibrosis in the white adipose tissue of obese mice, highlighting the role of HDAC4 in the liver-adipose axis.},
	doi = {10.1152/ajpgi.00225.2025},
	pmid = {41512278 [Indexed for MEDLINE]}
}

@ARTICLE{10.1096/fj.202501928RR,
	author = {de Oliveira ACC, Babêtto AM and Silva ML, de Souza Barbosa Lacerda L, de Souza Rodrigues T, de Oliveira MC and Rouault C and Gautier EL and Oliveira AG, Clément K and Teixeira MM and Marcelin G and Ferreira AVM},
	title = {TNF/TNFR1 is a Key Regulator of Prolonged Fasting-Induced Decrease in Adipose Tissue.},
	journal = {FASEB J},
	year = {2026},
	abstract = {Nutrient availability influences white adipose tissue (WAT) inflammation, leading to decreased or increased adiposity. Tumor necrosis factor (TNF) is elevated in WAT under both conditions, being involved in lipolysis and regulation of interleukin 18 (IL-18) secretion, which may regulate lipolytic processes. However, the role of these cytokines in adiposity reduction due to low energy availability remains unclear. Wild-type (WT) mice fasted for 24 h showed decreased adiposity, whereas TNFR1 knockout mice (TNFR1-/-) were unresponsive to fat pad loss, even after 48-h fasting. TNFR1-/- mice were also resistant to β3-adrenergic receptor agonist CL316,243-induced fat mobilization, which was linked with reduced expression of lipases, β3-adrenergic receptors, and cytokines in WAT. Also, mice treated with the TNF-α inhibitor infliximab and fasted for 48 h showed resistance to adiposity loss, suggesting that prolonged fasting-induced TNF signaling may modulate adipose tissue reduction. Conversely, IL-18 does not seem to influence fat pad loss induced by 24-h fasting as IL-18 knockout mice (IL-18-/-) express TNF in WAT and respond to prolonged fasting similarly to WT animals. To assess the potential translational relevance of our findings to human obesity, we analyzed 53 samples from patients with obesity who underwent bariatric surgery. Interestingly, TNFR1 and IL-18 expressions in sWAT correlate with the expression of lipases and adipokines in the subcutaneous site despite no correlation with body weight or fat mass 1 year after surgery. In summary, this study suggests that the TNF/TNFR1 axis is crucial for metabolic adaptation and is a prerequisite for prolonged fasting-induced lipolysis in male mice.},
	doi = {10.1096/fj.202501928RR},
	pmid = {41508774 [Indexed for MEDLINE]},
	note = {PMC12784137}
}

@ARTICLE{10.1016/j.ejphar.2026.178523,
	author = {Sun Y and Xia Y and Ge W and Li Q},
	title = {Tirzepatide reduces intracellular lipid content by promoting the browning of white fat via the cAMP signaling pathway.},
	journal = {Eur J Pharmacol},
	year = {2026},
	abstract = {Tirzepatide is well known for its glucose-lowering and weight-reducing effects, primarily through central appetite suppression. However, its direct role in promoting white adipose tissue (WAT) browning and the underlying mechanisms remain unclear. We investigated Tirzepatide's direct effects on WAT in high-fat diet (HFD)-induced obese mice. RNA sequencing was performed to assess transcriptional changes in WAT. In vitro, differentiated 3T3-L1 adipocytes were treated with Tirzepatide, with or without the adenylyl cyclase inhibitor SQ22536, to explore the involvement of cAMP-dependent signaling. Tirzepatide significantly reduced body weight as well as perirenal white adipose tissue (prWAT) and inguinal white adipose tissue (ingWAT) mass, accompanied by a marked reduction in adipocyte hypertrophy in obese mice. Transcriptomic analysis revealed a coordinated upregulation of gene programs involved in thermogenesis and lipid metabolism. These molecular changes were confirmed by immunoblotting and immunohistochemistry, which showed increased expression of browning markers, including peroxisome proliferator-activated receptor gamma coactivator 1-alpha (PGC-1α) and uncoupling protein 1 (UCP1), indicating a phenotypic shift of WAT toward a thermogenic state. In 3T3-L1 adipocytes, Tirzepatide activated the PGC-1α/UCP1 signaling axis in a cAMP-dependent manner, promoting white fat browning and reducing lipid droplet accumulation. The presence of SQ22536 attenuated these effects, highlighting cAMP signaling as a critical mediator of Tirzepatide's action. Collectively, these results demonstrate that Tirzepatide induces WAT browning via activation of the cAMP-PGC-1α-UCP1 signaling axis, leading to decreased lipid storage. These findings reveal a direct, adipocyte-intrinsic mechanism of action that extends Tirzepatide's therapeutic potential beyond its established effects on central appetite regulation.},
	doi = {10.1016/j.ejphar.2026.178523},
	pmid = {41506434 [Indexed for MEDLINE]}
}
